const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient({
    endpoint: process.env.COSMOS_ENDPOINT,
    key: process.env.COSMOS_KEY
});

const database = cosmosClient.database(process.env.COSMOS_DATABASE);
const container = database.container(process.env.COSMOS_CONTAINER);

app.http('batchDataProcessor', {
    methods: ['POST', 'GET'],
    authLevel: 'function',
    timeout: '00:10:00',
    handler: async (request, context) => {
        const startTime = Date.now();
        const maxExecutionTime = 9.5 * 60 * 1000;
        
        context.log('Starting batch data processing...');
        
        try {
            const batchSize = parseInt(request.query.get('batchSize')) || 1000;
            const maxItems = parseInt(request.query.get('maxItems')) || null;
            const operation = request.query.get('operation') || 'process';
            
            let processedCount = 0;
            let errorCount = 0;
            let continuationToken = null;
            const results = [];
            
            do {
                if (Date.now() - startTime > maxExecutionTime) {
                    context.log('Approaching timeout limit, stopping gracefully...');
                    break;
                }
                
                const querySpec = {
                    query: 'SELECT * FROM c'
                };
                
                const queryOptions = {
                    maxItemCount: batchSize,
                    continuationToken: continuationToken
                };
                
                const { resources: items, continuationToken: newToken } = await container.items
                    .query(querySpec, queryOptions)
                    .fetchNext();
                
                continuationToken = newToken;
                
                if (!items || items.length === 0) {
                    break;
                }
                
                context.log(`Processing batch of ${items.length} items...`);
                
                for (const item of items) {
                    try {
                        if (Date.now() - startTime > maxExecutionTime) {
                            break;
                        }
                        
                        const processedItem = await processItem(item, operation, context);
                        
                        if (processedItem.modified) {
                            await container.item(item.id, item.partitionKey).replace(processedItem.data);
                        }
                        
                        processedCount++;
                        results.push({
                            id: item.id,
                            status: 'success',
                            operation: operation
                        });
                        
                        if (maxItems && processedCount >= maxItems) {
                            context.log(`Reached maximum item limit: ${maxItems}`);
                            continuationToken = null;
                            break;
                        }
                        
                    } catch (itemError) {
                        errorCount++;
                        context.log(`Error processing item ${item.id}: ${itemError.message}`);
                        results.push({
                            id: item.id,
                            status: 'error',
                            error: itemError.message
                        });
                    }
                }
                
                if (processedCount % 5000 === 0) {
                    context.log(`Progress: ${processedCount} items processed, ${errorCount} errors`);
                }
                
            } while (continuationToken && (Date.now() - startTime < maxExecutionTime));
            
            const executionTime = (Date.now() - startTime) / 1000;
            
            const summary = {
                status: 'completed',
                processedCount: processedCount,
                errorCount: errorCount,
                executionTimeSeconds: executionTime,
                hasMoreData: !!continuationToken,
                continuationToken: continuationToken,
                timestamp: new Date().toISOString()
            };
            
            context.log(`Batch processing completed: ${JSON.stringify(summary)}`);
            
            return {
                status: 200,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    summary: summary,
                    results: results.slice(0, 100)
                })
            };
            
        } catch (error) {
            context.log(`Fatal error in batch processing: ${error.message}`);
            context.log(error.stack);
            
            return {
                status: 500,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    error: error.message,
                    stack: error.stack,
                    timestamp: new Date().toISOString()
                })
            };
        }
    }
});

async function processItem(item, operation, context) {
    switch (operation) {
        case 'transform':
            return transformItem(item);
        case 'aggregate':
            return aggregateItem(item);
        case 'validate':
            return validateItem(item);
        case 'enrich':
            return enrichItem(item);
        default:
            return processDefaultItem(item);
    }
}

function transformItem(item) {
    const transformed = {
        ...item,
        processed: true,
        processedAt: new Date().toISOString(),
        transformedData: {
            originalValue: item.value,
            transformedValue: item.value ? item.value.toString().toUpperCase() : null
        }
    };
    
    return {
        modified: true,
        data: transformed
    };
}

function aggregateItem(item) {
    const aggregated = {
        ...item,
        aggregatedAt: new Date().toISOString(),
        aggregations: {
            count: 1,
            sum: item.value || 0,
            average: item.value || 0
        }
    };
    
    return {
        modified: true,
        data: aggregated
    };
}

function validateItem(item) {
    const isValid = item.id && item.value !== undefined;
    
    const validated = {
        ...item,
        validatedAt: new Date().toISOString(),
        isValid: isValid,
        validationErrors: isValid ? [] : ['Missing required fields']
    };
    
    return {
        modified: true,
        data: validated
    };
}

function enrichItem(item) {
    const enriched = {
        ...item,
        enrichedAt: new Date().toISOString(),
        metadata: {
            ...item.metadata,
            enrichedFields: {
                timestamp: Date.now(),
                version: '1.0',
                source: 'batch-processor'
            }
        }
    };
    
    return {
        modified: true,
        data: enriched
    };
}

function processDefaultItem(item) {
    const processed = {
        ...item,
        lastProcessed: new Date().toISOString(),
        processCount: (item.processCount || 0) + 1
    };
    
    return {
        modified: true,
        data: processed
    };
}

